// @ts-ignore generated by opennextjs-cloudflare during cf:build
import generatedOpenNextWorker, { BucketCachePurge, DOQueueHandler, DOShardedTagCache } from "./.open-next/worker.js";

type OpenNextWorkerModule = {
  fetch(request: Request, env: CloudflareEnv, ctx: WorkerExecutionContext): Promise<Response>;
};

type WorkerExecutionContext = {
  waitUntil(promise: Promise<unknown>): void;
  passThroughOnException?(): void;
};

type WorkerScheduledController = {
  cron: string;
  scheduledTime: number;
};

type WorkerHandler = {
  fetch(request: Request, env: CloudflareEnv, ctx: WorkerExecutionContext): Promise<Response>;
  scheduled(controller: WorkerScheduledController, env: CloudflareEnv, ctx: WorkerExecutionContext): Promise<void>;
};

const openNextWorker = generatedOpenNextWorker as OpenNextWorkerModule;

async function runScheduledSync(env: CloudflareEnv, ctx: WorkerExecutionContext) {
  const origin = env.NEXT_PUBLIC_SITE_URL || "https://gospelchannel.com";
  const url = new URL("/api/cron/sync", origin);
  const headers = new Headers();

  if (env.CRON_SECRET) {
    headers.set("authorization", `Bearer ${env.CRON_SECRET}`);
  }

  const response = await openNextWorker.fetch(
    new Request(url.toString(), {
      method: "GET",
      headers,
    }),
    env,
    ctx,
  );

  if (!response.ok) {
    const details = (await response.text().catch(() => response.statusText)).slice(0, 200);
    throw new Error(`Scheduled sync failed with ${response.status}: ${details}`);
  }
}

export { BucketCachePurge, DOQueueHandler, DOShardedTagCache };

const worker: WorkerHandler = {
  fetch: openNextWorker.fetch,
  async scheduled(_controller: WorkerScheduledController, env: CloudflareEnv, ctx: WorkerExecutionContext) {
    await runScheduledSync(env, ctx);
  },
};

export default worker;
